CommonData.BannerCustomCSS:
/* BANNER */
div#onetrust-banner-sdk #onetrust-policy-text {
    font-family: "Gilroy", "Proxima Nova", sans-serif !important;
}
div#onetrust-banner-sdk #onetrust-policy-text.a {
    font-size: 8px;
}
div#onetrust-banner-sdk .ot-sdk-row:after {
    display: none !important;
}
div#onetrust-banner-sdk button {
    margin-bottom: 0.75rem;
}
div#onetrust-banner-sdk #onetrust-policy {
    margin: 1.25em 0.625em 2em;
}
div.ot-sdk-row {
    display: flex !important;
    justify-content: space-between;
}
div#onetrust-banner-sdk #onetrust-policy-title {
	font-size: 18px !important;
	display: flex !important;
	padding: 0 0 8px 0 !important;
	color: #0B3558 !important;
}
div#onetrust-button-group-parent {
    width: auto !important;
    position: relative !important;
    top: auto !important;
    left: auto !important;
    transform: none !important;
    float: none !important;
    justify-content: flex-end !important;
    margin: 0.5rem 2rem !important;
    display: flex !important;
    padding: 0 !important;
    flex: 0 0 auto !important;
    align-items: center !important;
}
div#onetrust-group-container {
    width: unset !important;
    position: relative !important;
    top: unset !important;
    left: unset !important;
    transform: unset !important;
    float: unset !important;
}
div#onetrust-button-group button {
    width: unset !important;
}
div#onetrust-button-group {
    margin-right: unset !important;
    margin-top: unset !important;
    display: flex !important;
}

div#onetrust-banner-sdk {
	max-width: 570px !important;
	font-family: "Gilroy", "Proxima Nova", sans-serif !important;
	padding: 24px !important;
	border-radius: 8px !important;
}
div#onetrust-banner-sdk .ot-sdk-container>.ot-sdk-row {
	display: block !important;
}
div#onetrust-banner-sdk .ot-optout-signal {
	margin: 0 0 16px 0 !important;
}
div#onetrust-banner-sdk >.ot-sdk-container>.ot-sdk-row {
	display: block !important;
}
div#onetrust-banner-sdk #onetrust-policy {
	margin: 0 !important;
}

div#onetrust-banner-sdk #onetrust-policy-text {
	font-size: 14px !important;
	padding: 0 !important;
}
div#onetrust-banner-sdk #onetrust-close-btn-container {
	top: -10px !important;
	right: -10px !important;
}
div#onetrust-banner-sdk .ot-close-icon {
	margin: 0;
	width: 24px;
	height: 24px;
}
div#onetrust-banner-sdk .ot-sdk-container {
	padding: 0 !important;
}
div#onetrust-banner-sdk #onetrust-policy-text a {
	margin-left: 0;
	font-weight: 400;
	color: #006bff !important;
}
div#onetrust-banner-sdk #onetrust-button-group-parent {
	margin: 16px 0 0 0!important;
	padding: 0 !important;
}
div#onetrust-banner-sdk #onetrust-button-group-parent #onetrust-button-group {
	display: flex;
	flex-direction: row-reverse;
	float: none;
	justify-content: space-between;
	align-items: center;
}
div#onetrust-banner-sdk #onetrust-button-group .onetrust-banner-options {
	display: flex !important;
	float: none !important;
	max-width: none !important;
	align-items: center;
	gap: 16px;
}
div#onetrust-banner-sdk #onetrust-button-group .onetrust-banner-options #onetrust-accept-btn-handler {
	margin: 0 !important;
	display: flex!important;
	font-size: 14px !important;
	border-radius: 8px;
	line-height: 1.2;
	justify-content: center;
	min-width: auto!important;
	align-items: center;
}
div#onetrust-banner-sdk #onetrust-button-group #onetrust-reject-all-handler {
	display: inline-flex;
	align-items: center;
	margin: 0 !important;
	padding: 0 !important;
	border: none !important;
	text-decoration: none !important;
	font-size: 14px !important;
	color: #006bff !important;
	background: transparent !important;
	max-width: fit-content !important;
	min-width: fit-content!important;
	min-height: 24px;
}
div#onetrust-banner-sdk #onetrust-button-group-parent .cookie-setting-link {
	display: inline-flex;
	align-items: center;
    gap: 4px;
	margin: 0 !important;
	padding: 0 !important;
	border: none !important;
	text-decoration: none !important;
	font-size: 14px !important;
	color: #006bff !important;
	background: transparent !important;
	max-width: fit-content !important;
	min-width: fit-content!important;
	min-height: 24px;
}
div#onetrust-banner-sdk #onetrust-button-group-parent .cookie-setting-link:hover::after {
	transform: translateX(4px)
}
div#onetrust-banner-sdk #onetrust-button-group-parent .cookie-setting-link::after {
	content: ' ';
	position: relative;
	width: 24px;
	height: 24px;
	transition: transform 0.1s linear;
	background-image: url("data:image/svg+xml;base64,");
}

/* Tablet */
@media screen and (max-width: 992px) {
	div#onetrust-banner-sdk {
		max-width: 700px !important;
		left: 50% !important;
		transform: translatex(-50%) !important;
	}
}

/* Mobile */
@media screen and (max-width: 480px) {
	div#onetrust-banner-sdk {
		left: 24px!important;
		right: 24px !important;
		bottom: 24px!important;
		transform: none !important;
		width: auto!important;
		min-width: auto;
	}
	div#onetrust-banner-sdk #onetrust-policy-title {
		font-size: 20px !important;
	}
	div#onetrust-banner-sdk #onetrust-button-group-parent #onetrust-button-group {
		flex-direction: column-reverse;
		justify-content: center;
		align-items: flex-start;
	}
	div#onetrust-banner-sdk #onetrust-button-group .onetrust-banner-options {
		margin-top: 8px;
		width: 100%!important;
	}
	div#onetrust-banner-sdk #onetrust-button-group .onetrust-banner-options #onetrust-accept-btn-handler {
		width: 100% !important;
	}
	div#onetrust-banner-sdk #onetrust-button-group .onetrust-banner-options button {
		min-width: 49% !important;
	}
}

CommonData.PCCustomCSS:
/* Preferece Center */
div#onetrust-pc-sdk #accept-recommended-btn-handler,
div#onetrust-pc-sdk .ot-pc-refuse-all-handler,
div#onetrust-pc-sdk .save-preference-btn-handler {
	border-radius: 8px;
	padding: 10px 16px;
	font-size: 0.875rem;
	line-height: 1.4;
	font-weight: 600 !important;
}
div#onetrust-pc-sdk .ot-tgl input:checked+.ot-switch .ot-switch-nob {
    background-color: #004EBA;
}
div#onetrust-pc-sdk .ot-switch-nob:before {
    height: 19px;
    width: 19px;
    bottom: 2px;
    left: 2px;
}
div#onetrust-pc-sdk .ot-tgl input:checked+.ot-switch .ot-switch-nob:before {
    transform: translateX(20px);
}
div#onetrust-pc-sdk .ot-accordion-layout .ot-cat-header {
	min-height: auto !important;
}
div#onetrust-pc-sdk .ot-plus-minus span {
	background: #476788 !important;
}
div#onetrust-pc-sdk #ot-category-title,
div#onetrust-pc-sdk #ot-pc-title {
	color: #0B3558 !important;
}
div#onetrust-pc-sdk .ot-pc-footer-logo {
	padding-right: 25px;
}
div#onetrust-pc-sdk .ot-pc-footer-logo a {
	height: 20px;
	margin-right: 0;
	width: fit-content;
}
div#onetrust-pc-sdk .ot-pc-header {
	display: flex;
    align-items: center;
    justify-content: space-between;
	padding: 10px 25px;
}
div#onetrust-pc-sdk .ot-pc-logo {
	width: fit-content;
}
div#onetrust-pc-sdk #close-pc-btn-handler {
	width: 24px;
	height: 24px;
	margin-right: -7px;
}
div#onetrust-pc-sdk #ot-pc-content {
	margin: 0;
    padding: 0 19px 0 25px;
    width: auto;
    overflow-y: scroll;
}
div#onetrust-pc-sdk .ot-pc-scrollbar::-webkit-scrollbar-thumb {
	border-radius: 8px !important;
}
#onetrust-pc-sdk .ot-pc-scrollbar::-webkit-scrollbar {
	width: 6px !important;
}

/* TABLET*/
@media only screen and (min-width: 567px) and (max-width: 900px) {
    div.ot-sdk-row {
        flex-direction: column !important;
    }
}

/* MOBILE */
@media only screen and (max-width: 567px) {
    div.ot-sdk-row {
        flex-direction: column !important;
    }
    div#onetrust-button-group {
        flex-direction: column-reverse;
        width: 100% !important;
    }
    div#onetrust-accept-btn-handler {
        text-align: center;
    }
    #onetrust-pc-sdk div#onetrust-button-group {
        width: unset !important;
    }
}
